import { buildReportListToolbarActions } from '@linm-soft/common-components';
import type { LinListToolbarActionDef } from '@linm-soft/common-components';

export type ReportListToolbarParams = {
  testIdPrefix: string;
  onRefresh: () => void;
  onEditConfig?: () => void;
  canPrint?: boolean;
  onPrint?: () => void;
};

export function buildKhoReportListToolbar(p: ReportListToolbarParams): LinListToolbarActionDef[] {
  return buildReportListToolbarActions({
    testIdPrefix: p.testIdPrefix,
    onRefresh: p.onRefresh,
    onEditConfig: p.onEditConfig,
    canPrint: p.canPrint,
    onPrint: p.onPrint,
  });
}
